public class Main {
    public static void main(String[] args) {
        String[] names = {"Alice", "Bob", "Carol"};

        for (int i = 0; i <= 3; i++) {  // i=3 is out of bounds!
            try {
                System.out.println("Accessing index " + i + ": " + names[i]);
            } catch (ArrayIndexOutOfBoundsException e) {
                System.out.println("Error at " + i + ": " + e.getMessage());
            } finally {
                System.out.println("--- finally ran ---");
            }
        }
    }
}

import java.io.IOException;

public class Main {
    // Declares it MIGHT throw IOException (checked) — caller must handle
    static void readFile(String path) throws IOException {
        if (!path.endsWith(".txt")) {
            throw new IOException("Not a text file: " + path);
        }
        System.out.println("Reading: " + path);
    }

    // Unchecked — no 'throws' needed
    static void process(String data) {
        if (data == null) throw new IllegalArgumentException("Data cannot be null");
        System.out.println("Processing: " + data);
    }

    public static void main(String[] args) {
        try {
            readFile("report.txt");    // OK
            readFile("config.xml");   // throws
        } catch (IOException e) {
            System.out.println("IOException: " + e.getMessage());
        }

        process("hello");  // OK
        try {
            process(null);
        } catch (IllegalArgumentException e) {
            System.out.println("IllegalArgument: " + e.getMessage());
        }
    }
}

instruction:
Catch multiple exception types in one catch block with `|`:

```java
catch (IOException | SQLException e) {
    // handles both
}
```

Or use multiple catch blocks for different handling. Catch from most specific to most general.

