public class Main {
    static int safeDivide(int a, int b) {
        return a / b;  // throws ArithmeticException if b=0
    }

    static int parseAndDouble(String s) {
        return Integer.parseInt(s) * 2;  // throws NumberFormatException
    }

    public static void main(String[] args) {
        String[] inputs = {"10", "abc", "5", null};
        int[] divisors  = {2, 0, 0, 3};

        for (int i = 0; i < inputs.length; i++) {
            try {
                int parsed = parseAndDouble(inputs[i]);
                int result = safeDivide(parsed, divisors[i]);
                System.out.println("Result: " + result);
            } catch (NumberFormatException e) {
                System.out.println("Bad number: " + inputs[i]);
            } catch (ArithmeticException e) {
                System.out.println("Division by zero!");
            } catch (NullPointerException e) {
                System.out.println("Null input!");
            }
        }
    }
}

