class InsufficientFundsException extends RuntimeException {
    private final double shortfall;

    InsufficientFundsException(double shortfall) {
        super(String.format("Insufficient funds. Shortfall: $%.2f", shortfall));
        this.shortfall = shortfall;
    }

    double getShortfall() { return shortfall; }
}

class BankAccount {
    private double balance;
    BankAccount(double bal) { balance = bal; }

    void withdraw(double amount) {
        if (amount > balance) throw new InsufficientFundsException(amount - balance);
        balance -= amount;
    }

    double getBalance() { return balance; }
}

public class Main {
    public static void main(String[] args) {
        BankAccount acc = new BankAccount(100.0);

        try {
            acc.withdraw(50);
            System.out.printf("Balance: $%.2f%n", acc.getBalance());
            acc.withdraw(200);  // throws
        } catch (InsufficientFundsException e) {
            System.out.println(e.getMessage());
            System.out.printf("Shortfall: $%.2f%n", e.getShortfall());
        }
    }
}

instruction:
Resources like file handles and database connections MUST be closed — even if an exception occurs.

`try-with-resources` automatically closes anything that implements `AutoCloseable`:

```java
try (Connection conn = getConnection()) {
    // conn is auto-closed when the block exits
}
```

No explicit finally needed.

starter:
class DatabaseConnection implements AutoCloseable {
    private boolean open = true;

    DatabaseConnection(String url) {
        System.out.println("Connecting to: " + url);
    }

    void query(String sql) {
        if (!open) throw new IllegalStateException("Connection is closed");
        System.out.println("Executing: " + sql);
    }

    @Override
    public void close() {
        open = false;
        System.out.println("Connection closed.");
    }
}

public class Main {
    public static void main(String[] args) {
        // try-with-resources: close() is called automatically!
        try (DatabaseConnection conn = new DatabaseConnection("jdbc:postgresql://localhost/db")) {
            conn.query("SELECT * FROM users");
            conn.query("SELECT * FROM orders");
        }  // conn.close() called here automatically

        System.out.println("After try block.");
    }
}
